<template>
  <img
    class="thumbnail-picture"
    draggable="false"
    loading="lazy"
    alt=""
    :key="previewFileId"
    :src="thumbnailUrl"
    :style="{
      width,
      height,
      'max-width': maxWidth,
      'max-height': maxHeight
    }"
    v-if="isPreviewWithThumbnail"
  />
  <span
    class="thumbnail-picture thumbnail-empty"
    :style="{
      width: emptyWidth ? emptyWidth : width,
      height: emptyHeight ? emptyHeight : height
    }"
    v-else
  >
  </span>
</template>

<script setup>
import { computed } from 'vue'

const props = defineProps({
  previewFileId: {
    type: String
  },
  extension: {
    type: String
  },
  width: {
    default: '150px',
    type: String
  },
  height: {
    default: '50px',
    type: String
  },
  maxHeight: {
    default: 'auto',
    type: String
  },
  maxWidth: {
    default: 'auto',
    type: String
  },
  emptyHeight: {
    type: String
  },
  emptyWidth: {
    type: String
  },
  type: {
    default: 'thumbnails',
    type: String
  },
  urlPrefix: {
    default: '',
    type: String
  }
})

const isPreviewWithThumbnail = computed(() => {
  return (
    props.previewFileId &&
    (!props.extension || ['mp4', 'png'].includes(props.extension))
  )
})

const thumbnailUrl = computed(() => {
  const base = props.urlPrefix || '/api'
  return `${base}/pictures/${props.type}/preview-files/${props.previewFileId}.png`
})
</script>

<style lang="scss" scoped>
.dark .thumbnail-picture {
  background-color: $dark-grey-lighter;
  border-color: $dark-grey-light;
}

span.thumbnail-empty {
  background: $white-grey;
  display: block;
  flex-shrink: 0;
  margin: 0;
}
</style>
